# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :title, :string
    field :content, :string
    field :sanitized_content, :string
    belongs_to :user, Blog.Accounts.User

    timestamps()
  end

  @allowed_tags ["p", "br", "strong", "em", "u", "h1", "h2", "h3", "h4",
                 "ul", "ol", "li", "blockquote", "pre", "code", "a", "img",
                 "table", "thead", "tbody", "tr", "th", "td", "hr", "span", "div"]

  @allowed_attributes ["href", "src", "alt", "title", "class"]

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content])
    |> validate_required([:title, :content])
    |> sanitize_content()
  end

  defp sanitize_content(changeset) do
    case get_change(changeset, :content) do
      nil ->
        changeset

      content ->
        sanitized = HtmlSanitizeEx.basic_html(content)
        put_change(changeset, :sanitized_content, sanitized)
    end
  end
end

# lib/blog_web/helpers/sanitize_helper.ex
defmodule BlogWeb.SanitizeHelper do
  @doc """
  Safely renders user-provided HTML by sanitizing it first.
  Never use raw() directly on user input.
  """
  def safe_html(nil), do: ""

  def safe_html(content) when is_binary(content) do
    content
    |> HtmlSanitizeEx.basic_html()
    |> Phoenix.HTML.raw()
  end
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  import BlogWeb.SanitizeHelper

  alias Blog.Posts

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)
    {:ok, assign(socket, :post, post)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <article class="prose lg:prose-xl">
        <h1><%= @post.title %></h1>

        <div class="post-meta text-gray-500 text-sm mb-6">
          <span>By <%= @post.user.name %></span>
          <span> · </span>
          <span><%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %></span>
        </div>

        <%!--
          SECURE: We use sanitized_content which was sanitized on save,
          and we sanitize again on render as defense-in-depth.

          NEVER DO THIS with user content:
            <%= raw @post.content %>

          ALWAYS sanitize first:
        --%>
        <div class="post-content">
          <%= safe_html(@post.sanitized_content) %>
        </div>
      </article>
    </div>
    """
  end
end

